def Interval := Nat × Nat

def nonoverlap (a b : Interval) : Prop := let (s1,e1) := a; let (s2,e2) := b; e1 ≤ s2 ∨ e2 ≤ s1

def compatible_set (xs : List Interval) : Prop := ∀ i j, i < xs.length → j < xs.length → i ≠ j → nonoverlap (xs.get ⟨i, ‹_›⟩) (xs.get ⟨j, ‹_›⟩)
